class Solution {
public:
    vector<int> beautifulIndices(string s, string a, string b, int k) {
        vector<int> result;
        int i = 0, j = 0;
        while (i < s.length() && j < b.length()) {
            if (s[i] == a[j] && s.substr(i, a.length()) == a && s.substr(j, b.length()) == b && abs(i - j) <= k) {
                result.push_back(i);
                i++; j++;
            }
            i++;
            j++;
        }
        return result;
    }
};
